import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavigationService } from '../../../service/native/navigation/navigation.service';

@Component({
  selector: 'app-header',
  standalone: true,
  imports: [CommonModule],
  template: `
  <div class="header">

    <!-- Header -->
    <p class="header_text">Swee Seng</p>

    <nav>
      <ul class="navigation" *ngFor="let configuredRoute of navigationService.ConfiguredRoutes">
        <li>{{ configuredRoute.title }}</li>
      </ul>
    </nav>
  </div>
  `,
  styleUrls: ['./header.component.css']
})
export class HeaderComponent {
  constructor(protected navigationService: NavigationService) { }
}
